  Dims2d() = default;
  /**
   * @param width Width (must be > 0)
   * @param height Height (must be > 0)
   */
  Dims2d(const int64_t width, const int64_t height)
  : w(static_cast<uint32_t>(width)), h(static_cast<uint32_t>(height))

bool LidarFRNetNode::setStaticCropBoxTransform(const std::string & sensor_frame_id)
{
  if (!tf_buffer_) {
    return false;
  }
  geometry_msgs::msg::TransformStamped tf;
  try {
    tf = tf_buffer_->lookupTransform(crop_reference_frame_, sensor_frame_id, tf2::TimePointZero);
  } catch (const tf2::TransformException & ex) {
    RCLCPP_WARN_THROTTLE(
      get_logger(), *get_clock(), 1000, "Ego crop box: TF lookup failed: %s", ex.what());
    return false;
  }
  const Eigen::Affine3d transform = tf2::transformToEigen(tf);
  std::array<float, 12> transform_out{};
  for (int r = 0; r < 3; ++r) {
    for (int c = 0; c < 3; ++c) {
      transform_out[r * 3 + c] = static_cast<float>(transform.linear()(r, c));
    }
    transform_out[9 + r] = static_cast<float>(transform.translation()(r));
  }
  crop_sensor_to_ref_.emplace(transform_out);
  tf_listener_.reset();
  tf_buffer_.reset();
  RCLCPP_INFO(
    get_logger(), "Ego crop box: cached static transform %s -> %s, TF listener shut down.",
    sensor_frame_id.c_str(), crop_reference_frame_.c_str());
  return true;
}

inline std::unique_ptr<cuda_blackboard::CudaPointCloud2> generatePointCloudMessageFromInput(
  const cuda_blackboard::CudaPointCloud2 & msg_in, const PointCloudLayout & layout,
  const size_t max_num_points)
{
  auto cloud_msg_ptr = std::make_unique<cuda_blackboard::CudaPointCloud2>();

  cloud_msg_ptr->data =
    cuda_blackboard::make_unique<std::uint8_t[]>(max_num_points * layout.point_step);

  cloud_msg_ptr->fields = layout.fields;
  cloud_msg_ptr->point_step = layout.point_step;
  cloud_msg_ptr->header = msg_in.header;
  cloud_msg_ptr->height = 1;
  cloud_msg_ptr->width = static_cast<uint32_t>(max_num_points);
  cloud_msg_ptr->row_step = layout.point_step * max_num_points;
  cloud_msg_ptr->is_bigendian = msg_in.is_bigendian;
  cloud_msg_ptr->is_dense = msg_in.is_dense;

  return cloud_msg_ptr;
}

bool LidarFRNet::process(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & cloud_in,
  cuda_blackboard::CudaPointCloud2 & cloud_seg_out,
  cuda_blackboard::CudaPointCloud2 & cloud_viz_out,
  cuda_blackboard::CudaPointCloud2 & cloud_filtered, CloudFormat filtered_output_format,
  const utils::ActiveComm & active_comm, std::unordered_map<std::string, double> & proc_timing,
  const std::array<float, 12> * crop_sensor_to_ref)
{
  stop_watch_ptr_->toc("processing/inner", true);
  std::call_once(init_cloud_, [this, &cloud_in]() {
    input_format_ = detectCloudFormat(*cloud_in);
    if (input_format_ == CloudFormat::UNKNOWN) {
      throw std::runtime_error(
        "Unsupported point cloud type. Expected one of: XYZIRCAEDT (10 fields), "
        "XYZIRADRT (9 fields), XYZIRC (6 fields), or XYZI (4 fields).");
    }
    input_point_step_ = get_point_step(input_format_);
    RCLCPP_INFO(
      logger_, "Detected input format with %zu fields and point step %zu bytes",
      get_num_fields(input_format_), input_point_step_);
  });

  const auto input_num_points = cloud_in->width * cloud_in->height;
  if (
    input_num_points < network_params_.num_points_profile.min ||
    input_num_points > network_params_.num_points_profile.max) {
    RCLCPP_ERROR(
      logger_,
      "Number of points (%d) in input pointcloud does not match the profile. Consider to update "
      "num_points in config file [min: %ld, opt: %ld, max: %ld].",
      input_num_points, network_params_.num_points_profile.min,
      network_params_.num_points_profile.opt, network_params_.num_points_profile.max);
    return false;
  }

  const auto max_num_elem = network_params_.num_points_profile.max * input_point_step_;
  cuda_utils::clear_async(cloud_in_d_.get(), max_num_elem, stream_);
  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    cloud_in_d_.get(), cloud_in->data.get(), input_point_step_ * input_num_points,
    cudaMemcpyDeviceToDevice, stream_));
  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));

  if (crop_sensor_to_ref != nullptr) {
    preprocess_ptr_->setCropBoxTransform(crop_sensor_to_ref->data());
  }

  if (!preprocess(input_num_points)) {
    RCLCPP_ERROR(logger_, "Preprocess failed.");
    return false;
  }
  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
  proc_timing.emplace(
    "debug/processing_time/preprocess_ms", stop_watch_ptr_->toc("processing/inner", true));

  if (!inference()) {
    RCLCPP_ERROR(logger_, "Inference failed.");
    return false;
  }
  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
  proc_timing.emplace(
    "debug/processing_time/inference_ms", stop_watch_ptr_->toc("processing/inner", true));

  if (!postprocess(
        num_points_, num_points_raw_, filtered_output_format, active_comm, cloud_seg_out,
        cloud_viz_out, cloud_filtered)) {
    RCLCPP_ERROR(logger_, "Postprocess failed.");
    return false;
  }
  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
  proc_timing.emplace(
    "debug/processing_time/postprocess_ms", stop_watch_ptr_->toc("processing/inner", true));

  return true;
}

bool LidarFRNet::preprocess(const uint32_t input_num_points)
{
  cuda_utils::clear_async(coors_keys_d_.get(), network_params_.num_points_profile.max, stream_);
  cuda_utils::clear_async(num_points_d_.get(), 1, stream_);
  cuda_utils::clear_async(
    proj_idxs_d_.get(), network_params_.interpolation.w * network_params_.interpolation.h, stream_);
  cuda_utils::clear_async(
    proj_2d_d_.get(), network_params_.interpolation.w * network_params_.interpolation.h, stream_);
  cuda_utils::clear_async(points_d_.get(), network_params_.num_points_profile.max * 4, stream_);
  cuda_utils::clear_async(coors_d_.get(), network_params_.num_points_profile.max * 3, stream_);
  cuda_utils::clear_async(
    voxel_coors_d_.get(), network_params_.num_unique_coors_profile.max * 3, stream_);
  cuda_utils::clear_async(inverse_map_d_.get(), network_params_.num_points_profile.max, stream_);
  uint32_t num_unique_coors{0};

  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
  CHECK_CUDA_ERROR(preprocess_ptr_->projectPoints_launch(
    cloud_in_d_.get(), input_num_points, input_format_, num_points_d_.get(), points_d_.get(),
    coors_d_.get(), coors_keys_d_.get(), proj_idxs_d_.get(), proj_2d_d_.get(),
    cloud_compact_d_.get()));
  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    &num_points_raw_, num_points_d_.get(), sizeof(uint32_t), cudaMemcpyDeviceToHost, stream_));
  CHECK_CUDA_ERROR(preprocess_ptr_->interpolatePoints_launch(
    proj_idxs_d_.get(), proj_2d_d_.get(), num_points_d_.get(), points_d_.get(), coors_d_.get(),
    coors_keys_d_.get()));

  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    &num_points_, num_points_d_.get(), sizeof(uint32_t), cudaMemcpyDeviceToHost, stream_));

  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));

  if (
    num_points_ < network_params_.num_points_profile.min ||
    num_points_ > network_params_.num_points_profile.max) {
    RCLCPP_ERROR(
      logger_,
      "Number of points (%d) after interpolation does not match the profile. Consider to update "
      "num_points in config file [min: %ld, opt: %ld, max: %ld].",
      num_points_, network_params_.num_points_profile.min, network_params_.num_points_profile.opt,
      network_params_.num_points_profile.max);
    return false;
  }

  preprocess_ptr_->generateUniqueCoors(
    num_points_, coors_d_.get(), coors_keys_d_.get(), num_unique_coors, voxel_coors_d_.get(),
    inverse_map_d_.get());

  if (
    num_unique_coors < network_params_.num_unique_coors_profile.min ||
    num_unique_coors > network_params_.num_unique_coors_profile.max) {
    RCLCPP_ERROR(
      logger_,
      "Number of unique coors (%d) does not match the profile. Consider to update num_unique_coors "
      "in "
      "config file [min: %ld, opt: %ld, max: %ld].",
      num_unique_coors, network_params_.num_unique_coors_profile.min,
      network_params_.num_unique_coors_profile.opt, network_params_.num_unique_coors_profile.max);
    return false;
  }

  network_ptr_->setInputShape("points", {2, {num_points_, 4}});
  network_ptr_->setInputShape("coors", {2, {num_points_, 3}});
  network_ptr_->setInputShape("voxel_coors", {2, {num_unique_coors, 3}});
  network_ptr_->setInputShape("inverse_map", {1, {num_points_}});

  return true;
}

cudaError_t PreprocessCuda::projectPoints_launch(
  const void * cloud, const uint32_t num_points, CloudFormat format, uint32_t * output_num_points,
  float * output_points, int64_t * output_coors, int64_t * output_coors_keys,
  uint32_t * output_proj_idxs, uint64_t * output_proj_2d, void * output_cloud_compact)
{
  switch (format) {
    case CloudFormat::XYZIRCAEDT:
      return projectPoints_launch_impl(
        static_cast<const CloudPointTypeXYZIRCAEDT *>(cloud), num_points, output_num_points,
        output_points, output_coors, output_coors_keys, output_proj_idxs, output_proj_2d,
        output_cloud_compact);
    case CloudFormat::XYZIRADRT:
      return projectPoints_launch_impl(
        static_cast<const CloudPointTypeXYZIRADRT *>(cloud), num_points, output_num_points,
        output_points, output_coors, output_coors_keys, output_proj_idxs, output_proj_2d,
        output_cloud_compact);
    case CloudFormat::XYZIRC:
      return projectPoints_launch_impl(
        static_cast<const CloudPointTypeXYZIRC *>(cloud), num_points, output_num_points,
        output_points, output_coors, output_coors_keys, output_proj_idxs, output_proj_2d,
        output_cloud_compact);
    case CloudFormat::XYZI:
      return projectPoints_launch_impl(
        static_cast<const CloudPointTypeXYZI *>(cloud), num_points, output_num_points,
        output_points, output_coors, output_coors_keys, output_proj_idxs, output_proj_2d,
        output_cloud_compact);
    default:
      return cudaErrorInvalidValue;
  }
}

cudaError_t PreprocessCuda::projectPoints_launch_impl(
  const PointT * cloud, const uint32_t num_points, uint32_t * output_num_points,
  float * output_points, int64_t * output_coors, int64_t * output_coors_keys,
  uint32_t * output_proj_idxs, uint64_t * output_proj_2d, void * output_cloud_compact)
{
  dim3 block(utils::divup(num_points, utils::kernel_1d_size));
  dim3 threads(utils::kernel_1d_size);

  projectPoints_kernel<<<block, threads, 0, stream_>>>(
    cloud, num_points, output_num_points, output_points, output_coors, output_coors_keys,
    output_proj_idxs, output_proj_2d, static_cast<PointT *>(output_cloud_compact));

  return cudaGetLastError();
}

__global__ void projectPoints_kernel(
  const PointT * cloud, const uint32_t num_points, uint32_t * output_num_points,
  float * output_points, int64_t * output_coors, int64_t * output_coors_keys,
  uint32_t * output_proj_idxs, uint64_t * output_proj_2d, PointT * output_cloud_compact)
{
  uint32_t point_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (point_idx >= num_points) return;

  const PointT & point = cloud[point_idx];
  const auto point3d = make_float3(point.x, point.y, point.z);

  // Ego crop box in reference frame: transform point to reference, then test AABB
  if (const_crop_box_enabled) {
    const float px = point3d.x, py = point3d.y, pz = point3d.z;
    const float p_ref_x = const_crop_box_sensor_to_ref[0] * px +
                          const_crop_box_sensor_to_ref[1] * py +
                          const_crop_box_sensor_to_ref[2] * pz + const_crop_box_sensor_to_ref[9];
    const float p_ref_y = const_crop_box_sensor_to_ref[3] * px +
                          const_crop_box_sensor_to_ref[4] * py +
                          const_crop_box_sensor_to_ref[5] * pz + const_crop_box_sensor_to_ref[10];
    const float p_ref_z = const_crop_box_sensor_to_ref[6] * px +
                          const_crop_box_sensor_to_ref[7] * py +
                          const_crop_box_sensor_to_ref[8] * pz + const_crop_box_sensor_to_ref[11];
    if (
      p_ref_x > const_crop_box_bounds[0] && p_ref_x < const_crop_box_bounds[3] &&
      p_ref_y > const_crop_box_bounds[1] && p_ref_y < const_crop_box_bounds[4] &&
      p_ref_z > const_crop_box_bounds[2] && p_ref_z < const_crop_box_bounds[5]) {
      return;
    }
  }

  const uint32_t append_idx = atomicAdd(output_num_points, 1);
  const float intensity = get_intensity(point);
  const auto proj_point = project2d(point3d, const_interpolation.w, const_interpolation.h);
  const auto proj_coor = project2d(point3d, const_frustum.w, const_frustum.h);
  const auto proj_idx = proj_point.y * const_interpolation.w + proj_point.x;

  output_points[append_idx * 4 + 0] = point.x;
  output_points[append_idx * 4 + 1] = point.y;
  output_points[append_idx * 4 + 2] = point.z;
  output_points[append_idx * 4 + 3] = intensity;

  output_coors[append_idx * 3 + 0] = 0;
  output_coors[append_idx * 3 + 1] = proj_coor.y;
  output_coors[append_idx * 3 + 2] = proj_coor.x;

  output_coors_keys[append_idx] = proj_coor.y * const_frustum.w + proj_coor.x;

  if (output_cloud_compact != nullptr) {
    output_cloud_compact[append_idx] = point;
  }

  // Update projection: first point or atomic max-by-depth
  auto point_half4 = half4(point.x, point.y, point.z, intensity);
  auto output_proj_2d_address = reinterpret_cast<unsigned long long *>(&output_proj_2d[proj_idx]);
  if (!atomicExch(&output_proj_idxs[proj_idx], 1)) {
    *output_proj_2d_address = pack_half4(point_half4);
  } else {
    atomicMaxByDepth_half4(output_proj_2d_address, point_half4);
  }
}

__device__ int2 project2d(const float3 point, const uint32_t scale_x, const uint32_t scale_y)
{
  float depth = sqrtf(point.x * point.x + point.y * point.y + point.z * point.z);
  float yaw = -atan2f(point.y, point.x);
  float pitch = asinf(point.z / depth);
  float proj_x = 0.5f * (yaw / M_PIf + 1.0f);
  float proj_y = 1.0f - (pitch + fabs(const_fov.down)) / const_fov.total;
  proj_x *= static_cast<float>(scale_x);
  proj_y *= static_cast<float>(scale_y);
  return make_int2(
    static_cast<int32_t>(fminf(fmaxf(proj_x, 0.0f), static_cast<float>(scale_x) - 1.0f)),
    static_cast<int32_t>(fminf(fmaxf(proj_y, 0.0f), static_cast<float>(scale_y) - 1.0f)));
}

__device__ void atomicMaxByDepth_half4(unsigned long long * address, const half4 & new_val)
{
  half4 old_val;
  unsigned long long old_packed = *address;

  while (true) {
    unpack_half4(old_packed, old_val);

    float depth_old = __half2float(old_val.x) * __half2float(old_val.x) +
                      __half2float(old_val.y) * __half2float(old_val.y) +
                      __half2float(old_val.z) * __half2float(old_val.z);

    float depth_new = __half2float(new_val.x) * __half2float(new_val.x) +
                      __half2float(new_val.y) * __half2float(new_val.y) +
                      __half2float(new_val.z) * __half2float(new_val.z);

    if (depth_new <= depth_old) return;

    unsigned long long new_packed = pack_half4(new_val);
    unsigned long long prev = atomicCAS(address, old_packed, new_packed);

    if (prev == old_packed) break;

    old_packed = prev;  // retry
  }
}

__device__ inline void unpack_half4(unsigned long long packed, half4 & h)
{
  auto p = reinterpret_cast<uint16_t *>(&packed);
  h.x = __ushort_as_half(p[0]);
  h.y = __ushort_as_half(p[1]);
  h.z = __ushort_as_half(p[2]);
  h.w = __ushort_as_half(p[3]);
}

__device__ inline unsigned long long pack_half4(const half4 & h)
{
  unsigned long long packed = 0;
  auto p = reinterpret_cast<uint16_t *>(&packed);
  p[0] = __half_as_ushort(h.x);
  p[1] = __half_as_ushort(h.y);
  p[2] = __half_as_ushort(h.z);
  p[3] = __half_as_ushort(h.w);
  return packed;
}

cudaError_t PreprocessCuda::interpolatePoints_launch(
  uint32_t * proj_idxs, uint64_t * proj_2d, uint32_t * output_num_points, float * output_points,
  int64_t * output_coors, int64_t * output_coors_keys)
{
  dim3 block(
    utils::divup(interpolation_.w, utils::kernel_2d_size),
    utils::divup(interpolation_.h, utils::kernel_2d_size));
  dim3 threads(utils::kernel_2d_size, utils::kernel_2d_size);

  interpolatePoints_kernel<<<block, threads, 0, stream_>>>(
    proj_idxs, proj_2d, output_num_points, output_points, output_coors, output_coors_keys);

  return cudaGetLastError();
}

__global__ void interpolatePoints_kernel(
  const uint32_t * proj_idxs, uint64_t * proj_2d, uint32_t * output_num_points,
  float * output_points, int64_t * output_coors, int64_t * output_coors_keys)
{
  uint32_t x = blockIdx.x * blockDim.x + threadIdx.x;
  uint32_t y = blockIdx.y * blockDim.y + threadIdx.y;

  if (x >= const_interpolation.w || y >= const_interpolation.h) return;

  uint32_t idx = y * const_interpolation.w + x;

  if (proj_idxs[idx]) {
    return;  // Skip if the pixel is already filled
  }

  // Interpolate from left and right neighbors
  if (x > 0 && x < const_interpolation.w - 1) {
    if (
      proj_idxs[(y * const_interpolation.w) + (x - 1)] &&
      proj_idxs[(y * const_interpolation.w) + (x + 1)]) {
      // Interpolate points
      half4 left, right;
      unpack_half4(proj_2d[idx - 1], left);
      unpack_half4(proj_2d[idx + 1], right);

      // Compute the mean of the valid neighbors
      const auto interpolated_point = make_float4(
        (__half2float(left.x + right.x)) * 0.5f, (__half2float(left.y + right.y)) * 0.5f,
        (__half2float(left.z + right.z)) * 0.5f, (__half2float(left.w + right.w)) * 0.5f);

      auto append_idx = atomicAdd(output_num_points, 1);
      output_points[append_idx * 4 + 0] = interpolated_point.x;
      output_points[append_idx * 4 + 1] = interpolated_point.y;
      output_points[append_idx * 4 + 2] = interpolated_point.z;
      output_points[append_idx * 4 + 3] = interpolated_point.w;

      const auto proj_coor = project2d(
        make_float3(interpolated_point.x, interpolated_point.y, interpolated_point.z),
        const_frustum.w, const_frustum.h);

      output_coors[append_idx * 3 + 0] = 0;
      output_coors[append_idx * 3 + 1] = proj_coor.y;
      output_coors[append_idx * 3 + 2] = proj_coor.x;

      output_coors_keys[append_idx] = proj_coor.y * const_frustum.w + proj_coor.x;
    }
  }
}

__device__ int2 project2d(const float3 point, const uint32_t scale_x, const uint32_t scale_y)
{
  float depth = sqrtf(point.x * point.x + point.y * point.y + point.z * point.z);
  float yaw = -atan2f(point.y, point.x);
  float pitch = asinf(point.z / depth);
  float proj_x = 0.5f * (yaw / M_PIf + 1.0f);
  float proj_y = 1.0f - (pitch + fabs(const_fov.down)) / const_fov.total;
  proj_x *= static_cast<float>(scale_x);
  proj_y *= static_cast<float>(scale_y);
  return make_int2(
    static_cast<int32_t>(fminf(fmaxf(proj_x, 0.0f), static_cast<float>(scale_x) - 1.0f)),
    static_cast<int32_t>(fminf(fmaxf(proj_y, 0.0f), static_cast<float>(scale_y) - 1.0f)));
}

__device__ inline void unpack_half4(unsigned long long packed, half4 & h)
{
  auto p = reinterpret_cast<uint16_t *>(&packed);
  h.x = __ushort_as_half(p[0]);
  h.y = __ushort_as_half(p[1]);
  h.z = __ushort_as_half(p[2]);
  h.w = __ushort_as_half(p[3]);
}

void PreprocessCuda::generateUniqueCoors(
  const uint32_t num_points, const int64_t * coors, const int64_t * coors_keys,
  uint32_t & output_num_unique_coors, int64_t * output_voxel_coors, int64_t * output_inverse_map)
{
  // Input unordered coors
  thrust::device_vector<Coord> coors_d(
    reinterpret_cast<const Coord *>(coors), reinterpret_cast<const Coord *>(coors) + num_points);

  // Original indices of coors
  thrust::device_vector<int64_t> sorted_idxs(num_points);
  thrust::sequence(thrust::cuda::par.on(stream_), sorted_idxs.begin(), sorted_idxs.end(), 0);

  // Sort indices by coors keys
  thrust::device_vector<int64_t> coors_keys_d(num_points);
  int64_t * d_sorted_keys_output_ptr = thrust::raw_pointer_cast(coors_keys_d.data());
  int64_t * d_values_inout_ptr = thrust::raw_pointer_cast(sorted_idxs.data());
  void * d_temp_storage = nullptr;
  size_t temp_storage_bytes = 0;
  // If num_points is 0, CUB SortPairs is a no-op and temp_storage_bytes will be 0
  cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes, coors_keys, d_sorted_keys_output_ptr, d_values_inout_ptr,
    d_values_inout_ptr, num_points, 0, sizeof(int64_t) * 8, stream_);

  // Allocate temporary storage
  thrust::device_vector<u_char> cub_temp_storage_buffer_d(temp_storage_bytes);
  if (temp_storage_bytes > 0) {  // Only assign if memory is actually needed
    d_temp_storage = thrust::raw_pointer_cast(cub_temp_storage_buffer_d.data());
  } else {
    d_temp_storage = nullptr;  // Ensure d_temp_storage is nullptr if no bytes are needed
  }

  // Perform the sort if there are points to sort
  if (num_points > 0) {
    cub::DeviceRadixSort::SortPairs(
      d_temp_storage, temp_storage_bytes, coors_keys, d_sorted_keys_output_ptr, d_values_inout_ptr,
      d_values_inout_ptr, num_points, 0, sizeof(int64_t) * 8, stream_);
  }

  // Reorder coors based on the sorted indices
  thrust::device_vector<Coord> coors_sorted(num_points);
  thrust::gather(
    thrust::cuda::par.on(stream_), sorted_idxs.begin(), sorted_idxs.end(), coors_d.begin(),
    coors_sorted.begin());

  // Generate inverse_map for the sorted coors
  thrust::device_vector<int64_t> idxs_update(num_points);

  auto not_equal = [] __device__(const Coord & a, const Coord & b) { return a == b ? 0 : 1; };
  thrust::transform(
    thrust::cuda::par.on(stream_), coors_sorted.begin(), coors_sorted.end() - 1,
    coors_sorted.begin() + 1, idxs_update.begin() + 1, not_equal);

  thrust::device_vector<int64_t> labels(num_points);
  thrust::inclusive_scan(
    thrust::cuda::par.on(stream_), idxs_update.begin(), idxs_update.end(), labels.begin());

  thrust::scatter(
    thrust::cuda::par.on(stream_), labels.begin(), labels.end(), sorted_idxs.begin(),
    output_inverse_map);

  // Generate unique coors
  auto new_end = thrust::unique_copy(
    thrust::cuda::par.on(stream_), coors_sorted.begin(), coors_sorted.end(),
    reinterpret_cast<Coord *>(output_voxel_coors));
  output_num_unique_coors = new_end - reinterpret_cast<Coord *>(output_voxel_coors);
}

bool TrtCommon::setInputShape(const char * tensor_name, const nvinfer1::Dims & dimensions)
{
  if (!context_) {
    logger_->log(nvinfer1::ILogger::Severity::kERROR, "Context is not initialized");
    return false;
  }
  auto success = context_->setInputShape(tensor_name, dimensions);
  if (!success) {
    logger_->log(
      nvinfer1::ILogger::Severity::kERROR, "Failed to set input shape for tensor: ", tensor_name);
  }
  return success;
}

bool LidarFRNet::inference()
{
  network_ptr_->enqueueV3(stream_);
  return true;
}

bool TrtCommon::enqueueV3(cudaStream_t stream)
{
  if (!context_) {
    logger_->log(nvinfer1::ILogger::Severity::kERROR, "Context is not initialized");
    return false;
  }
  if (trt_config_->profile_per_layer) {
    auto inference_start = std::chrono::high_resolution_clock::now();
    auto success = context_->enqueueV3(stream);
    auto inference_end = std::chrono::high_resolution_clock::now();
    host_profiler_->reportLayerTime(
      "inference_host",
      std::chrono::duration<float, std::milli>(inference_end - inference_start).count());
    return success;
  }
  return context_->enqueueV3(stream);
}

bool enqueueV3(cudaStream_t stream) noexcept
{
    return mImpl->enqueueV3(stream);
}

bool LidarFRNet::postprocess(
  const uint32_t num_points, const uint32_t num_points_raw, CloudFormat filtered_output_format,
  const utils::ActiveComm & active_comm, cuda_blackboard::CudaPointCloud2 & cloud_seg_out,
  cuda_blackboard::CudaPointCloud2 & cloud_viz_out,
  cuda_blackboard::CudaPointCloud2 & cloud_filtered)
{
  cuda_utils::clear_async(seg_data_d_.get(), network_params_.num_points_profile.max, stream_);
  cuda_utils::clear_async(viz_data_d_.get(), network_params_.num_points_profile.max, stream_);
  const auto max_filtered_buffer_size =
    network_params_.num_points_profile.max * cloud_filtered.point_step;
  cuda_utils::clear_async(cloud_filtered_d_.get(), max_filtered_buffer_size, stream_);
  cuda_utils::clear_async(num_points_filtered_d_.get(), 1, stream_);
  uint32_t num_points_filtered{0};

  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
  CHECK_CUDA_ERROR(postprocess_ptr_->fillCloud_launch(
    points_d_.get(), cloud_compact_d_.get(), num_points_raw, pred_probs_d_.get(), num_points,
    input_format_, filtered_output_format, active_comm, num_points_filtered_d_.get(),
    seg_data_d_.get(), viz_data_d_.get(), cloud_filtered_d_.get()));
  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));

  if (active_comm.seg) {
    CHECK_CUDA_ERROR(cudaMemcpyAsync(
      cloud_seg_out.data.get(), seg_data_d_.get(), sizeof(OutputSegmentationPointType) * num_points,
      cudaMemcpyDeviceToDevice, stream_));
    CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
    cloud_seg_out.width = num_points;
    cloud_seg_out.height = 1;
    cloud_seg_out.row_step = num_points * cloud_seg_out.point_step;
  }

  if (active_comm.viz) {
    CHECK_CUDA_ERROR(cudaMemcpyAsync(
      cloud_viz_out.data.get(), viz_data_d_.get(),
      sizeof(OutputVisualizationPointType) * num_points, cudaMemcpyDeviceToDevice, stream_));
    CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
    cloud_viz_out.width = num_points;
    cloud_viz_out.height = 1;
    cloud_viz_out.row_step = num_points * cloud_viz_out.point_step;
  }

  if (active_comm.filtered) {
    CHECK_CUDA_ERROR(cudaMemcpyAsync(
      &num_points_filtered, num_points_filtered_d_.get(), sizeof(uint32_t), cudaMemcpyDeviceToHost,
      stream_));
    CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
    CHECK_CUDA_ERROR(cudaMemcpyAsync(
      cloud_filtered.data.get(), cloud_filtered_d_.get(),
      cloud_filtered.point_step * num_points_filtered, cudaMemcpyDeviceToDevice, stream_));
    CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
    cloud_filtered.width = num_points_filtered;
    cloud_filtered.row_step = num_points_filtered * cloud_filtered.point_step;
  }
  return true;
}

cudaError_t PostprocessCuda::fillCloud_launch(
  const float * points_xyzi, const void * cloud_compact, const uint32_t num_points_raw,
  const float * pred_probs, const uint32_t num_points, CloudFormat input_format,
  CloudFormat output_format, const utils::ActiveComm & active_comm,
  uint32_t * output_num_points_filtered, OutputSegmentationPointType * output_cloud_seg,
  OutputVisualizationPointType * output_cloud_viz, void * output_cloud_filtered)
{
  switch (input_format) {
    case CloudFormat::XYZIRCAEDT:
      switch (output_format) {
        case CloudFormat::XYZIRCAEDT:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRCAEDT *>(cloud_compact),
            num_points_raw, pred_probs, num_points, active_comm, output_num_points_filtered,
            output_cloud_seg, output_cloud_viz,
            static_cast<CloudPointTypeXYZIRCAEDT *>(output_cloud_filtered));
        case CloudFormat::XYZIRC:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRCAEDT *>(cloud_compact),
            num_points_raw, pred_probs, num_points, active_comm, output_num_points_filtered,
            output_cloud_seg, output_cloud_viz,
            static_cast<CloudPointTypeXYZIRC *>(output_cloud_filtered));
        case CloudFormat::XYZI:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRCAEDT *>(cloud_compact),
            num_points_raw, pred_probs, num_points, active_comm, output_num_points_filtered,
            output_cloud_seg, output_cloud_viz,
            static_cast<CloudPointTypeXYZI *>(output_cloud_filtered));
        default:
          return cudaErrorInvalidValue;
      }
    case CloudFormat::XYZIRADRT:
      switch (output_format) {
        case CloudFormat::XYZIRADRT:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRADRT *>(cloud_compact),
            num_points_raw, pred_probs, num_points, active_comm, output_num_points_filtered,
            output_cloud_seg, output_cloud_viz,
            static_cast<CloudPointTypeXYZIRADRT *>(output_cloud_filtered));
        case CloudFormat::XYZI:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRADRT *>(cloud_compact),
            num_points_raw, pred_probs, num_points, active_comm, output_num_points_filtered,
            output_cloud_seg, output_cloud_viz,
            static_cast<CloudPointTypeXYZI *>(output_cloud_filtered));
        default:
          return cudaErrorInvalidValue;
      }
    case CloudFormat::XYZIRC:
      switch (output_format) {
        case CloudFormat::XYZIRC:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRC *>(cloud_compact), num_points_raw,
            pred_probs, num_points, active_comm, output_num_points_filtered, output_cloud_seg,
            output_cloud_viz, static_cast<CloudPointTypeXYZIRC *>(output_cloud_filtered));
        case CloudFormat::XYZI:
          return fillCloud_launch_impl(
            points_xyzi, static_cast<const CloudPointTypeXYZIRC *>(cloud_compact), num_points_raw,
            pred_probs, num_points, active_comm, output_num_points_filtered, output_cloud_seg,
            output_cloud_viz, static_cast<CloudPointTypeXYZI *>(output_cloud_filtered));
        default:
          return cudaErrorInvalidValue;
      }
    case CloudFormat::XYZI:
      if (output_format == CloudFormat::XYZI) {
        return fillCloud_launch_impl(
          points_xyzi, static_cast<const CloudPointTypeXYZI *>(cloud_compact), num_points_raw,
          pred_probs, num_points, active_comm, output_num_points_filtered, output_cloud_seg,
          output_cloud_viz, static_cast<CloudPointTypeXYZI *>(output_cloud_filtered));
      }
      return cudaErrorInvalidValue;
    default:
      return cudaErrorInvalidValue;
  }
}

cudaError_t PostprocessCuda::fillCloud_launch_impl(
  const float * points_xyzi, const InputPointT * cloud_compact, const uint32_t num_points_raw,
  const float * pred_probs, const uint32_t num_points, const utils::ActiveComm & active_comm,
  uint32_t * output_num_points_filtered, OutputSegmentationPointType * output_cloud_seg,
  OutputVisualizationPointType * output_cloud_viz, OutputPointT * output_cloud_filtered)
{
  dim3 block(utils::divup(num_points, utils::kernel_1d_size));
  dim3 threads(utils::kernel_1d_size);

  fill_cloud_kernel<<<block, threads, 0, stream_>>>(
    points_xyzi, cloud_compact, num_points_raw, pred_probs, num_points, active_comm.seg,
    active_comm.viz, active_comm.filtered, output_num_points_filtered, output_cloud_seg,
    output_cloud_viz, output_cloud_filtered);

  return cudaGetLastError();
}

__global__ void fill_cloud_kernel(
  const float * points_xyzi, const InputPointT * cloud_compact, const uint32_t num_points_raw,
  const float * pred_probs, const uint32_t num_points, const bool active_comm_seg,
  const bool active_comm_viz, const bool active_comm_filtered,
  uint32_t * output_num_points_filtered, OutputSegmentationPointType * output_cloud_seg,
  OutputVisualizationPointType * output_cloud_viz, OutputPointT * output_cloud_filtered)
{
  uint32_t point_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (point_idx >= num_points) {
    return;
  }

  const float x = points_xyzi[point_idx * 4 + 0];
  const float y = points_xyzi[point_idx * 4 + 1];
  const float z = points_xyzi[point_idx * 4 + 2];
  const uint32_t pred_idx = point_idx * const_num_classes;

  float best_prob = -1e9;
  uint32_t class_id = const_num_classes - 1;

  // Find the best prob and class_id
  for (uint32_t i = 0; i < const_num_classes; i++) {
    float prob = pred_probs[pred_idx + i];
    if (prob > best_prob) {
      best_prob = prob;
      class_id = i;
    }
  }

  if (active_comm_seg) {
    output_cloud_seg[point_idx].x = x;
    output_cloud_seg[point_idx].y = y;
    output_cloud_seg[point_idx].z = z;
    output_cloud_seg[point_idx].class_id = static_cast<uint8_t>(class_id);
    output_cloud_seg[point_idx].probability = best_prob;
  }

  if (active_comm_viz) {
    output_cloud_viz[point_idx].x = x;
    output_cloud_viz[point_idx].y = y;
    output_cloud_viz[point_idx].z = z;
    output_cloud_viz[point_idx].rgb = const_palette[class_id];
  }

  if (active_comm_filtered) {
    bool is_filtered = false;
    for (uint32_t i = 0; i < const_num_filter_classes; ++i) {
      uint32_t class_idx = const_filter_class_indices[i];
      float prob = pred_probs[pred_idx + class_idx];
      if (prob >= const_filter_class_probability_threshold) {
        is_filtered = true;  // mark point as filtered
        break;
      }
    }
    if (!is_filtered) {  // if point is not filtered, add it to the output cloud
      const uint32_t append_idx = atomicAdd(output_num_points_filtered, 1);
      if (cloud_compact != nullptr && point_idx < num_points_raw) {
        set_point_from_input(output_cloud_filtered[append_idx], cloud_compact[point_idx]);
      } else {
        set_point_from_xyzi(output_cloud_filtered[append_idx], points_xyzi, point_idx);
      }
    }
  }
}

__device__ void set_point_from_input(OutputPointT & output_point, const InputPointT & input_point);

template <>
__device__ void set_point_from_input<CloudPointTypeXYZI, CloudPointTypeXYZI>(
  CloudPointTypeXYZI & output_point, const CloudPointTypeXYZI & input_point)
{
  output_point = input_point;
}

__device__ void set_point_from_xyzi(PointT & point, const float * points_xyzi, uint32_t point_idx);

template <>
__device__ void set_point_from_xyzi<CloudPointTypeXYZI>(
  CloudPointTypeXYZI & point, const float * points_xyzi, uint32_t point_idx)
{
  const uint32_t base = point_idx * 4;
  point.x = points_xyzi[base + 0];
  point.y = points_xyzi[base + 1];
  point.z = points_xyzi[base + 2];
  point.intensity = points_xyzi[base + 3];
}
